function DrawSunburst() {
  const { Sunburst } = components;
  const primaryDimension = "dimension_column";
  const secondaryDimension = "secondary_dimension_column";
  const measureField = "measure_column";
  const grouped = data.reduce((result, item) => {
    const primary = String(item[primaryDimension]);
    let parent = result.find((node) => node.name === primary);
    if (!parent) {
      parent = { name: primary, children: [] };
      result.push(parent);
    }
    parent.children.push({
      name: String(item[secondaryDimension] ?? primary),
      value: Number(item[measureField]) || 0
    });
    return result;
  }, []);
  const config = {
    data: { name: "root", children: grouped },
    innerRadius: 0.2,
    interactions: [{ type: "element-active" }]
  };
  return <div><Sunburst {...config} /></div>;
}
